"use client";

import React, { useState } from "react";
import type { AgentRunResult } from "@/lib/agents/schemas";

// ─── State system (UNCHANGED) ─────────────────────────────────────────────────
type AgentState = "idle"|"bull"|"bear"|"alert"|"approved"|"blocked"|"armed"|"analyzing";
interface SC { accent:string; screen:string; badge:string }

const STATE:Record<AgentState,SC> = {
  idle:      {accent:"#1e3a5f", screen:"#020810", badge:"IDLE"      },
  bull:      {accent:"#00ff9c", screen:"#001a0a", badge:"BULLISH"   },
  bear:      {accent:"#ff4466", screen:"#180006", badge:"BEARISH"   },
  alert:     {accent:"#ffaa00", screen:"#100800", badge:"ALERT"     },
  approved:  {accent:"#00ff9c", screen:"#001a0a", badge:"VALID"     },
  blocked:   {accent:"#ff4466", screen:"#180006", badge:"BLOCKED"   },
  armed:     {accent:"#00ffee", screen:"#001210", badge:"ARMED"     },
  analyzing: {accent:"#22d3ee", screen:"#010c10", badge:"ANALYZING" },
};

function deriveStates(d:AgentRunResult):Record<string,AgentState> {
  const {agents} = d;
  const bias = agents.master.finalBias;
  return {
    trend:
      agents.trend.bias==="bullish"&&agents.trend.confidence>=52?"bull":
      agents.trend.bias==="bearish"&&agents.trend.confidence>=52?"bear":
      agents.trend.confidence<35?"idle":"alert",
    smc:
      agents.smc.liquiditySweepDetected?"alert":
      agents.smc.setupPresent&&agents.smc.bias==="bullish"?"bull":
      agents.smc.setupPresent&&agents.smc.bias==="bearish"?"bear":
      agents.smc.confidence<35?"idle":"alert",
    news:
      agents.news.riskScore>=65?"alert":
      agents.news.impact==="bullish"?"bull":
      agents.news.impact==="bearish"?"bear":"idle",
    risk:       agents.risk.valid?"approved":"blocked",
    contrarian:
      agents.contrarian.challengesBias&&agents.contrarian.trapConfidence>=60?"blocked":
      agents.contrarian.challengesBias?"alert":"idle",
    master:
      bias==="bullish"&&agents.master.confidence>=65?"bull":
      bias==="bearish"&&agents.master.confidence>=65?"bear":
      bias==="no-trade"?"analyzing":"alert",
    execution:
      agents.execution.hasSetup&&agents.risk.valid&&bias!=="no-trade"?"armed":
      agents.execution.hasSetup?"alert":"idle",
  };
}

// ─── Agent pin config ─────────────────────────────────────────────────────────
// Positions as % of image (detected from user-annotated circles)
interface PinConfig {
  id: string;
  stateKey: string;
  label: string;
  role: string;
  px: number; // left %
  py: number; // top %
  isMaster?: boolean;
}

const PINS: PinConfig[] = [
  { id:"trend",      stateKey:"trend",      label:"TREND",      role:"Macro Bias Analyst",         px:27.08, py:39.65 },
  { id:"priceaction",stateKey:"smc",        label:"PR. ACTION", role:"Price Action Analyst",       px:42.97, py:41.70 },
  { id:"newsintel",  stateKey:"news",       label:"NEWS INTEL", role:"Fundamentals Analyst",       px:62.76, py:47.85 },
  { id:"mastercmo",  stateKey:"master",     label:"MASTER CMO", role:"Chief Market Officer",       px:80.40, py:50.10, isMaster:true },
  { id:"riskrate",   stateKey:"risk",       label:"RISK RATE",  role:"Risk Management Agent",      px:13.09, py:57.03 },
  { id:"contrarian", stateKey:"contrarian", label:"CONTRARIAN", role:"Counter-Signal Analyst",     px:42.64, py:69.24 },
  { id:"execution",  stateKey:"execution",  label:"EXECUTION",  role:"Entry Timing Agent",         px:72.66, py:77.05 },
];

const AGENT_DESC: Record<string,string> = {
  trend:      "HTF structure is bearish. HH/HL sequence broken on H4. Price trading below key institutional EMA. Order flow points short.",
  smc:        "Bearish engulfing confirmed on M15. Strong supply zone rejection at 4,711. No bullish demand candles visible. Structure break imminent.",
  news:       "USD index slightly weak post-CPI. Gold fundamentally supported short-term. No major risk events in next 4 hours.",
  master:     "77% weighted bearish consensus across all 7 agents. Strategy match: Sweep & Reverse Short. Highs swept, structure break confirmed.",
  risk:       "Maximum 1% risk per trade. Recommended lot: 0.053 on $10k. Stop loss 18.8pts above sweep. RR ratio: 2.0:1.",
  contrarian: "Minor oversold on M5 RSI (28.4). Slight MACD divergence on M5. Insufficient to flip bias — bearish confirmed.",
  execution:  "Entry zone expired 0.95% from entry. DO NOT CHASE. Wait for next sweep + reversal candle confirmation on M5/M15.",
};

const HQ_IMAGE = "data:image/png;base64,";

// ─── Main component ───────────────────────────────────────────────────────────
export function AgentCommandRoom({ data, loading=false }: {
  data: AgentRunResult|null; loading?: boolean;
}) {
  const [activeId, setActiveId] = useState<string|null>(null);

  const states: Record<string,AgentState> = data
    ? deriveStates(data)
    : { trend:"idle", smc:"idle", news:"idle", risk:"idle", contrarian:"idle", master:"analyzing", execution:"idle" };

  const sc = (key: string): SC => STATE[states[key] ?? "idle"];
  const activePinData = PINS.find(p => p.id === activeId);
  const activeSC = activePinData ? sc(activePinData.stateKey) : null;
  const activeState = activePinData ? (states[activePinData.stateKey] ?? "idle") : null;

  const masterSC = sc("master");
  const conf = data?.agents.master.confidence ?? 0;
  const finalBias = data?.agents.master.finalBias ?? "no-trade";
  const biasColor = finalBias==="bullish"?"#00ff9c":finalBias==="bearish"?"#ff4466":"#ffaa00";
  const biasLabel = finalBias==="bullish"?"▲ BULLISH":finalBias==="bearish"?"▼ BEARISH":"— NO TRADE";

  return (
    <div className="w-full rounded-xl border border-cyan-500/20 bg-[#060d1a] overflow-hidden">

      {/* ── IMAGE + PINS ── */}
      <div style={{ position:"relative", width:"100%" }}>
        <img
          src={HQ_IMAGE}
          alt="TradeX Agent HQ"
          style={{ width:"100%", display:"block", imageRendering:"pixelated" }}
        />

        {/* Bias overlay bar on top of image */}
        <div style={{
          position:"absolute", top:0, left:0, right:0,
          background:"linear-gradient(180deg, rgba(6,13,26,0.85) 0%, transparent 100%)",
          padding:"10px 16px",
          display:"flex", justifyContent:"space-between", alignItems:"center",
          pointerEvents:"none",
        }}>
          <span style={{ color:"#22d3ee", fontSize:10, letterSpacing:"0.22em", fontFamily:"ui-monospace,monospace" }}>
            ⚡ TRADEX · MULTI-AGENT FLOOR
          </span>
          <div style={{ display:"flex", alignItems:"center", gap:12 }}>
            <span style={{ color:biasColor, fontSize:13, fontWeight:700, letterSpacing:"0.15em", fontFamily:"ui-monospace,monospace" }}>
              {biasLabel}
            </span>
            <div style={{
              background:"#0a1e3a", borderRadius:2, overflow:"hidden",
              width:80, height:4,
            }}>
              <div style={{ width:`${conf}%`, height:"100%", background:biasColor }} />
            </div>
            <span style={{ color:biasColor, fontSize:10, fontFamily:"ui-monospace,monospace" }}>{conf}%</span>
          </div>
        </div>

        {/* Agent pins */}
        {PINS.map(pin => {
          const pinSC = sc(pin.stateKey);
          const pinState = states[pin.stateKey] ?? "idle";
          const isIdle = pinState === "idle";
          const isActive = activeId === pin.id;
          const isAlert = pinState === "blocked" || pinState === "alert";
          const accent = pinSC.accent;

          return (
            <div
              key={pin.id}
              onClick={() => setActiveId(isActive ? null : pin.id)}
              style={{
                position:"absolute",
                left:`${pin.px}%`,
                top:`${pin.py}%`,
                transform:"translate(-50%,-50%)",
                cursor:"pointer",
                zIndex:10,
              }}
            >
              {/* Outer pulse ring */}
              <div style={{
                position:"absolute",
                top:"50%", left:"50%",
                transform:"translate(-50%,-50%)",
                width: isActive ? 52 : 38,
                height: isActive ? 52 : 38,
                borderRadius:"50%",
                border:`2px solid ${accent}`,
                opacity: isIdle ? 0.25 : isActive ? 1 : 0.6,
                transition:"all 0.2s",
                boxShadow: isActive ? `0 0 16px ${accent}` : isIdle ? "none" : `0 0 6px ${accent}55`,
                animation: isAlert ? "none" : undefined,
                pointerEvents:"none",
              }} />

              {/* Center dot */}
              <div style={{
                width:14, height:14,
                borderRadius:"50%",
                background:"#060d1a",
                border:`2.5px solid ${accent}`,
                position:"relative",
                zIndex:2,
                transform: isActive ? "scale(1.35)" : "scale(1)",
                boxShadow: isActive ? `0 0 14px ${accent}` : "none",
                transition:"transform 0.18s, box-shadow 0.18s",
              }}>
                <div style={{
                  position:"absolute", inset:3,
                  borderRadius:"50%",
                  background:accent,
                  opacity: isIdle ? 0.3 : 0.9,
                }} />
              </div>

              {/* Master crown */}
              {pin.isMaster && (
                <div style={{
                  position:"absolute",
                  bottom:"calc(100% + 2px)",
                  left:"50%",
                  transform:"translateX(-50%)",
                  color:accent,
                  fontSize:10,
                  opacity: isActive ? 1 : 0.5,
                  textShadow:`0 0 8px ${accent}`,
                  pointerEvents:"none",
                  fontFamily:"ui-monospace,monospace",
                }}>★</div>
              )}

              {/* Tooltip */}
              <div style={{
                position:"absolute",
                bottom:"calc(100% + 10px)",
                left:"50%",
                transform:"translateX(-50%)",
                whiteSpace:"nowrap",
                fontSize:8,
                letterSpacing:"0.14em",
                padding:"3px 8px",
                borderRadius:2,
                border:`1px solid ${accent}`,
                color:accent,
                background:"#040608ee",
                opacity: isActive ? 1 : 0,
                pointerEvents:"none",
                transition:"opacity 0.15s",
                fontFamily:"ui-monospace,monospace",
              }}>
                {pin.isMaster ? "★ " : ""}{pin.label}
              </div>

              {/* Active halo glow on image */}
              {isActive && (
                <div style={{
                  position:"absolute",
                  top:"50%", left:"50%",
                  transform:"translate(-50%,-50%)",
                  width:90, height:90,
                  borderRadius:"50%",
                  background:`radial-gradient(circle, ${accent} 0%, transparent 70%)`,
                  opacity:0.12,
                  pointerEvents:"none",
                }} />
              )}
            </div>
          );
        })}
      </div>

      {/* ── DETAIL PANEL ── */}
      <div style={{
        borderTop:`1px solid ${activeSC ? activeSC.accent + "44" : "#1a2535"}`,
        padding:"12px 20px",
        minHeight:88,
        display:"flex",
        alignItems:"center",
        background:"#07090f",
        transition:"border-color 0.3s",
      }}>
        {activePinData && activeSC ? (
          <div style={{ display:"flex", gap:16, alignItems:"center", width:"100%" }}>
            {/* Info */}
            <div style={{ flex:1 }}>
              <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:4, flexWrap:"wrap" }}>
                <span style={{
                  color:activeSC.accent,
                  fontSize:16, fontWeight:700,
                  letterSpacing:"0.18em",
                  fontFamily:"ui-monospace,monospace",
                }}>
                  {activePinData.isMaster ? "★ " : ""}{activePinData.label}
                </span>
                <span style={{
                  fontSize:8, letterSpacing:"0.12em",
                  padding:"2px 7px", borderRadius:2,
                  border:`1px solid ${activeSC.accent}`,
                  color:activeSC.accent,
                  background:activeSC.accent + "18",
                  fontFamily:"ui-monospace,monospace",
                }}>
                  {activeSC.badge}
                </span>
                <span style={{ color:"#445566", fontSize:8, fontFamily:"ui-monospace,monospace", letterSpacing:"0.1em" }}>
                  {activePinData.role}
                </span>
              </div>
              <div style={{ color:"#667788", fontSize:10, lineHeight:1.8, maxWidth:480, fontFamily:"ui-monospace,monospace" }}>
                {AGENT_DESC[activePinData.stateKey]}
              </div>
            </div>

            {/* Score/confidence */}
            <div style={{
              background:"#0a0d14",
              border:`1px solid ${activeSC.accent}44`,
              borderRadius:3, padding:"12px 18px",
              textAlign:"center", minWidth:80,
            }}>
              <div style={{ fontSize:7, color:"#2a3a4a", letterSpacing:"0.15em", marginBottom:5, fontFamily:"ui-monospace,monospace" }}>
                CONFIDENCE
              </div>
              <div style={{
                fontSize:30, fontWeight:700,
                color: activeState==="bull"||activeState==="approved"||activeState==="armed" ? "#00ff9c" : "#ff4466",
                lineHeight:1,
                textShadow:`0 0 18px ${activeSC.accent}`,
                fontFamily:"ui-monospace,monospace",
              }}>
                {data ? (
                  activePinData.stateKey==="master" ? `${conf}%` :
                  activePinData.stateKey==="trend" ? `${data.agents.trend.confidence}%` :
                  activePinData.stateKey==="smc" ? `${data.agents.smc.confidence}%` :
                  activePinData.stateKey==="news" ? `${data.agents.news.riskScore}` :
                  "—"
                ) : "—"}
              </div>
              <div style={{
                marginTop:6, fontSize:8,
                color:activeSC.accent,
                border:`1px solid ${activeSC.accent}`,
                background:activeSC.accent + "18",
                padding:"1px 6px", borderRadius:2,
                fontFamily:"ui-monospace,monospace",
                letterSpacing:"0.1em",
              }}>
                {activeSC.badge}
              </div>
            </div>
          </div>
        ) : (
          <div style={{ display:"flex", flexDirection:"column", alignItems:"center", width:"100%", gap:6 }}>
            <div style={{ color:"#1e2d3d", fontSize:9, letterSpacing:"0.2em", fontFamily:"ui-monospace,monospace" }}>
              ▲ CLICK AN AGENT TO VIEW THEIR ANALYSIS
            </div>
            <div style={{ display:"flex", gap:10 }}>
              {PINS.map(p => {
                const psc = sc(p.stateKey);
                return (
                  <div key={p.id} onClick={() => setActiveId(p.id)}
                    style={{ width:5, height:5, borderRadius:"50%", background:psc.accent, opacity:0.3, cursor:"pointer" }}
                  />
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
